pub struct ExecutorRegistry { executors: HashMap<Address, ExecutorInfo>, max_executors: usize }

pub fn new(max_executors: usize) -> Self { Self { executors: HashMap::new(), max_executors } }

pub fn register_executor(&mut self, address: Address, executor_info: ExecutorInfo) {
    if self.executors.len() >= self.max_executors { self.remove_oldest_inactive(); }
    self.executors.insert(address, executor_info);
}

fn remove_oldest_inactive(&mut self) { ... filter(|(_, info)| !info.is_active).min_by_key(|(_, info)| info.registration_time) ... }
